import{_ as t,c as r,l as a,a as l,t as s,a4 as i,o}from"./chunks/framework.CzsDe1xi.js";const f=JSON.parse('{"title":"Mysql分库分表","description":"","frontmatter":{"title":"Mysql分库分表"},"headers":[],"relativePath":"doc/数据库/Mysql/架构/分库和分表/分库分表方案.md","filePath":"packages/doc/src/数据库/Mysql/架构/分库和分表/分库分表方案.md","lastUpdated":1711637456000}'),h={name:"doc/数据库/Mysql/架构/分库和分表/分库分表方案.md"},d={id:"frontmatter-title",tabindex:"-1"},n=a("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),c=i('<h2 id="水平拆分表" tabindex="-1">水平拆分表 <a class="header-anchor" href="#水平拆分表" aria-label="Permalink to &quot;水平拆分表&quot;">​</a></h2><p>是按照某种规则，将一个表的数据分散到多个物理独立的数据库服务器中，形成“独立”的数据库“分片”。多个分片共同组成一个逻辑完整的数据库实例。</p><p>常规的单机数据库中，一张完整的表仅在一个物理存储设备上读写。</p><p>数据的切分通常就需要找到一个分表键（shardkey）以确定拆分维度，再采用某个字段求模（HASH）的方案进行分表，而计算 HASH 的某个字段就是 shardkey。 HASH 算法能够基本保证数据相对均匀地分散在不同的物理设备中。</p><p>数据聚合：如果一个查询 SQL 语句的数据涉及到多个分表，此时 SQL 会被路由到多个分表执行，TDSQL MySQL版 会将各个分表返回的数据按照原始 SQL 语义进行合并，并将最终结果返回给用户。</p><p>注意：</p><p>执行 SELECT 语句时，建议您在 where 条件带上 shardKey 字段，否则会导致数据需要全表扫描然后网关才对执行结果进行聚合。全表扫描响应较慢，对性能影响很大。</p><h2 id="读取数据-有明确-shardkey-值" tabindex="-1">读取数据（有明确 shardkey 值） <a class="header-anchor" href="#读取数据-有明确-shardkey-值" aria-label="Permalink to &quot;读取数据（有明确 shardkey 值）&quot;">​</a></h2><ol><li>业务发送 select 请求中含有 shardkey 时，网关通过对 shardkey 进行 hash。</li><li>不同的 hash 值范围对应不同的分片。</li><li>数据根据分片算法，将数据从对应的分片中取出。</li></ol><h3 id="读取数据-无明确-shardkey-值" tabindex="-1">读取数据（无明确 shardkey 值） <a class="header-anchor" href="#读取数据-无明确-shardkey-值" aria-label="Permalink to &quot;读取数据（无明确 shardkey 值）&quot;">​</a></h3><ol><li>业务发送 select 请求没有 shardkey 时，将请求发往所有分片。</li><li>各个分片查询自身内容，发回 Proxy 。</li><li>Proxy 根据 SQL 规则，对数据进行聚合，再答复给网关。</li></ol><h2 id="_2-垂直拆分表" tabindex="-1">2.垂直拆分表 <a class="header-anchor" href="#_2-垂直拆分表" aria-label="Permalink to &quot;2.垂直拆分表&quot;">​</a></h2><h2 id="_3-读写分离" tabindex="-1">3.读写分离 <a class="header-anchor" href="#_3-读写分离" aria-label="Permalink to &quot;3.读写分离&quot;">​</a></h2><h2 id="_4-弹性扩展" tabindex="-1">4.弹性扩展 <a class="header-anchor" href="#_4-弹性扩展" aria-label="Permalink to &quot;4.弹性扩展&quot;">​</a></h2><h2 id="_5-强同步" tabindex="-1">5.强同步 <a class="header-anchor" href="#_5-强同步" aria-label="Permalink to &quot;5.强同步&quot;">​</a></h2><p>传统数据复制方式有如下三种：</p><ul><li>异步复制：应用发起更新请求，主节点（Master） 完成相应操作后立即响应应用，Master 向从节点（Slave）异步复制数据。</li><li>强同步复制：应用发起更新请求，Master 完成操作后向 Slave 复制数据，Slave 接收到数据后向 Master 返回成功信息，Master 接到 Slave 的反馈后再应答给应用。Master 向 Slave 复制数据是同步进行的。</li><li>半同步复制：应用发起更新请求，Master 在执行完更新操作后立即向 Slave 复制数据，Slave 接收到数据并写到 relay log 中（无需执行） 后才向 Master 返回成功信息，Master 必须在接受到 Slave 的成功信息后再向应用程序返回响应。</li></ul><p>当 Master 或 Slave 不可用时，以上三种传统数据复制方式均有几率引起数据不一致。</p><p>数据库作为系统数据存储和服务的核心能力，其可用性要求非常高。在生产系统中，通常都需要用高可用方案来保证系统不间断运行，而数据同步技术是数据库高可用方案的基础。</p><h2 id="_6-分布式事务问题" tabindex="-1">6.分布式事务问题 <a class="header-anchor" href="#_6-分布式事务问题" aria-label="Permalink to &quot;6.分布式事务问题&quot;">​</a></h2>',20);function _(e,p,k,S,y,u){return o(),r("div",null,[a("h1",d,[l(s(e.$frontmatter.title)+" ",1),n]),c])}const q=t(h,[["render",_]]);export{f as __pageData,q as default};
